    15→type TestEnvironment struct {
    16→	Config       Config
    17→	TransflowCLI *TransflowCLI
    18→	cleanup      []func()
    19→}
    20→
    21→type Config struct {
    22→	UseRealServices bool
    23→	CleanupAfter    bool
    24→	InjectFailures  bool
    25→	TimeoutMinutes  int
    26→}
    27→
    28→func SetupTestEnvironment(t *testing.T, config Config) *TestEnvironment {
    29→	env := &TestEnvironment{Config: config}
    30→
    31→	if config.UseRealServices {
    32→		env.setupRealServices(t)
    33→	} else {
    34→		env.setupMockServices(t)
    35→	}
    36→
    37→	return env
    38→}
    39→
    40→func (env *TestEnvironment) setupRealServices(t *testing.T) {
    41→	if os.Getenv("TARGET_HOST") != "" {
    42→		env.setupVPSServices(t)
    43→	} else {
    44→		testutils.RequireServices(t, "consul", "nomad", "seaweedfs")
    45→		env.setupLocalServices(t)
    46→	}
    47→}
    48→
    49→func (env *TestEnvironment) setupLocalServices(t *testing.T) {
    50→	env.TransflowCLI = &TransflowCLI{
    51→		binaryPath: "./bin/ploy",
    52→		env: map[string]string{
    53→			"CONSUL_HTTP_ADDR":  "localhost:8500",
    54→			"NOMAD_ADDR":        "http://localhost:4646",
    55→			"SEAWEEDFS_MASTER":  "http://localhost:9333",
    56→			"SEAWEEDFS_FILER":   "http://localhost:8888",
    57→		},
    58→	}
    59→}
    60→
    61→func (env *TestEnvironment) setupVPSServices(t *testing.T) {
    62→	targetHost := os.Getenv("TARGET_HOST")
    63→	env.TransflowCLI = &TransflowCLI{
    64→		binaryPath: "./bin/ploy-linux",
    65→		env: map[string]string{
    66→			"TARGET_HOST": targetHost,
    67→		},
    68→	}
    69→}
    70→
    71→func (env *TestEnvironment) setupMockServices(t *testing.T) {
    72→	env.TransflowCLI = &TransflowCLI{
    73→		binaryPath: "./bin/ploy",
    74→		env: map[string]string{
    75→			"TRANSFLOW_TEST_MODE": "true",
    76→		},
    77→	}
    78→}
