    80→func (env *TestEnvironment) ExecuteWorkflow(ctx context.Context, workflow *TransflowWorkflow) (WorkflowResult, error) {
    81→	yamlContent, err := workflow.ToYAML()
    82→	if err != nil {
    83→		return WorkflowResult{}, fmt.Errorf("failed to generate workflow YAML: %w", err)
    84→	}
    85→
    86→	tempFile := filepath.Join(os.TempDir(), fmt.Sprintf("transflow-%s.yaml", workflow.ID))
    87→	err = os.WriteFile(tempFile, []byte(yamlContent), 0644)
    88→	if err != nil {
    89→		return WorkflowResult{}, fmt.Errorf("failed to write workflow file: %w", err)
    90→	}
    91→	defer os.Remove(tempFile)
    92→
    93→	start := time.Now()
    94→	output, err := env.TransflowCLI.Run(ctx, "transflow", "run", "-f", tempFile)
    95→	duration := time.Since(start)
    96→
    97→	result := WorkflowResult{
    98→		ID:       workflow.ID,
    99→		Duration: duration,
   100→		Success:  err == nil,
   101→		Output:   output,
   102→	}
   103→
   104→	if err != nil {
   105→		result.Error = err.Error()
   106→	}
   107→
   108→	result.parseFromOutput(output)
   109→	return result, nil
   110→}
   111→
   112→func (env *TestEnvironment) Cleanup() {
   113→	for _, cleanup := range env.cleanup {
   114→		cleanup()
   115→	}
   116→}
