   118→type TransflowCLI struct {
   119→	binaryPath string
   120→	env        map[string]string
   121→}
   122→
   123→func (cli *TransflowCLI) Run(ctx context.Context, args ...string) (string, error) {
   124→	if os.Getenv("TARGET_HOST") != "" {
   125→		return cli.runVPS(ctx, args...)
   126→	}
   127→	return cli.runLocal(ctx, args...)
   128→}
   129→
   130→func (cli *TransflowCLI) runLocal(ctx context.Context, args ...string) (string, error) {
   131→	cmd := exec.CommandContext(ctx, cli.binaryPath, args...)
   132→	cmd.Env = os.Environ()
   133→	for k, v := range cli.env {
   134→		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
   135→	}
   136→	output, err := cmd.CombinedOutput()
   137→	return string(output), err
   138→}
   139→
   140→func (cli *TransflowCLI) runVPS(ctx context.Context, args ...string) (string, error) {
   141→	targetHost := os.Getenv("TARGET_HOST")
   142→	cmdArgs := append([]string{
   143→		fmt.Sprintf("root@%s", targetHost),
   144→		"su - ploy -c", 
   145→		fmt.Sprintf("'/opt/ploy/bin/ploy %s'", args[0])}, args[1:]...)
   146→	
   147→	if len(args) > 1 {
   148→		cmdArgs[2] = fmt.Sprintf("'/opt/ploy/bin/ploy %s'", fmt.Sprintf("%s %s", args[0], args[1]))
   149→		if len(args) > 2 {
   150→			for _, arg := range args[2:] {
   151→				cmdArgs[2] += " " + arg
   152→			}
   153→		}
   154→	}
   155→	
   156→	cmd := exec.CommandContext(ctx, "ssh", "-o", "ConnectTimeout=30", cmdArgs[0], cmdArgs[1], cmdArgs[2])
   157→	output, err := cmd.CombinedOutput()
   158→	return string(output), err
   159→}

