     9→func parseHealingAttempts(output string) []HealingAttempt {
    10→	var attempts []HealingAttempt
    11→	
    12→	// Simple parsing for healing attempts from output
    13→	lines := strings.Split(output, "\n")
    14→	
    15→	var currentAttempt *HealingAttempt
    16→	
    17→	for _, line := range lines {
    18→		line = strings.TrimSpace(line)
    19→		
    20→		// Look for healing attempt markers
    21→		if strings.Contains(strings.ToLower(line), "healing attempt") {
    22→			if currentAttempt != nil {
    23→				attempts = append(attempts, *currentAttempt)
    24→			}
    25→			currentAttempt = &HealingAttempt{}
    26→		}
    27→		
    28→		if currentAttempt == nil {
    29→			continue
    30→		}
    31→		
    32→		// Parse error signature
    33→		if strings.Contains(strings.ToLower(line), "error signature") || 
    34→		   strings.Contains(strings.ToLower(line), "error:") {
    35→			currentAttempt.ErrorSignature = extractErrorSignature(line)
    36→		}
    37→		
    38→		// Parse success
    39→		if strings.Contains(strings.ToLower(line), "success") &&
    40→		   strings.Contains(strings.ToLower(line), "healing") {
    41→			currentAttempt.Success = true
    42→		}
    43→		
    44→		// Parse confidence
    45→		confidenceRegex := regexp.MustCompile(`confidence:\s+([0-9.]+)`)
    46→		if matches := confidenceRegex.FindStringSubmatch(line); len(matches) > 1 {
    47→			if conf, err := strconv.ParseFloat(matches[1], 64); err == nil {
    48→				currentAttempt.Confidence = conf
    49→			}
    50→		}
    51→	}
    52→	
    53→	if currentAttempt != nil {
    54→		attempts = append(attempts, *currentAttempt)
    55→	}
    56→	
    57→	return attempts
    58→}
    59→
    60→func extractErrorSignature(line string) string {
    61→	// Extract error signature from line
    62→	if idx := strings.Index(strings.ToLower(line), "error"); idx != -1 {
    63→		remaining := line[idx:]
    64→		if colonIdx := strings.Index(remaining, ":"); colonIdx != -1 {
    65→			sig := strings.TrimSpace(remaining[colonIdx+1:])
    66→			if len(sig) > 100 {
    67→				sig = sig[:100] + "..."
    68→			}
    69→			return sig
    70→		}
    71→	}
    72→	return "unknown-error"
    73→}

